SELECT A.SEQ, A.RESUME_SEQ, A.PERSON_ID, A.EMPID, A.LOCAL_NAME, A.DEPTNO, GET_DEPT_NAME(A.DEPTNO, #{lang, jdbcType=VARCHAR}) DEPTNAME, A.POST_GRADE_NO, A.POST_GRADE_NAME, A.MAIN_BUSINESS, GET_GLOBAL_NAME(A.MAIN_BUSINESS, #{lang, jdbcType=VARCHAR}) MAIN_BUSINESS_NAME, A.OBJECT_TYPE, A.OBJECT_TYPE_NAME, TO_CHAR(A.DATE_STARTED, 'YYYY-MM-DD') DATE_STARTED, A.ACTIVITY, GET_CODE_NAME(A.ACTIVITY, #{lang, jdbcType=VARCHAR}) ACTIVITY_NAME, DECODE(A.FINAL_GRADE,'A','EX','B','VG','C','GD','D','NI','E','UN') FINAL_GRADE, A.FINAL_GRADE FINAL_GRADE_OR, A.FINAL_AFFIRM_CONTENT, TO_CHAR(A.UPDATE_DATE, 'DD/MM/YYYY HH24:MI') UPDATE_DATE, GET_UPDATED_INFO(A.UPDATED_BY) || ' ' || A.UPDATED_IP UPDATED_BY, A.ORDERNO, DECODE(PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'AFFIRM_FLAG'), 1, 'Evaluated', 0, 'Not_Evaluated') AFFIRM_FLAG_NAME0, DECODE(PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'AFFIRM_FLAG'), 1, 'Evaluated', 0, 'Not_Evaluated') AFFIRM_FLAG_NAME1, DECODE(PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'AFFIRM_FLAG'), 1, 'Evaluated', 0, 'Not_Evaluated') AFFIRM_FLAG_NAME2, DECODE(PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'AFFIRM_FLAG'), 1, 'Evaluated', 0, 'Not_Evaluated') AFFIRM_FLAG_NAME3, DECODE(PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'AFFIRM_FLAG'), 1, 'Evaluated', 0, 'Not_Evaluated') AFFIRM_FLAG_NAME4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'LOCAL_NAME') LOCAL_NAME0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'LOCAL_NAME') LOCAL_NAME1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'LOCAL_NAME') LOCAL_NAME2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'LOCAL_NAME') LOCAL_NAME3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'LOCAL_NAME') LOCAL_NAME4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'POST_GRADE_NAME') POST_GRADE_NAME0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'POST_GRADE_NAME') POST_GRADE_NAME1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'POST_GRADE_NAME') POST_GRADE_NAME2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'POST_GRADE_NAME') POST_GRADE_NAME3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'POST_GRADE_NAME') POST_GRADE_NAME4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'SEQ') SEQ0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'SEQ') SEQ1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'SEQ') SEQ2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'SEQ') SEQ3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'SEQ') SEQ4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'EVS_POINT') EVS_POINT0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'EVS_POINT') EVS_POINT1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'EVS_POINT') EVS_POINT2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'EVS_POINT') EVS_POINT3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'EVS_POINT') EVS_POINT4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'EVS_GRADE') EVS_GRADE0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'EVS_GRADE') EVS_GRADE1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'EVS_GRADE') EVS_GRADE2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'EVS_GRADE') EVS_GRADE3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'EVS_GRADE') EVS_GRADE4, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'AFFIRM_CONTENT') || CHR(10) || PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 0, 'AFFIRM_CONTENT2') AFFIRM_CONTENT0, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'AFFIRM_CONTENT') AFFIRM_CONTENT1, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 2, 'AFFIRM_CONTENT') AFFIRM_CONTENT2, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 3, 'AFFIRM_CONTENT') AFFIRM_CONTENT3, PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 4, 'AFFIRM_CONTENT') AFFIRM_CONTENT4 FROM EVS_OBJECT A WHERE A.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND A.DEPTNO IN
#{dno, jdbcType=VARCHAR}
AND A.PERSON_ID = #{personId, jdbcType=VARCHAR}
AND PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'AFFIRM_FLAG') = 1
AND PKG_EVS_PROCESS.GET_EVS_AFFIRM_INFO(A.SEQ, 1, 'AFFIRM_FLAG') = 0
ORDER BY A.PERSON_ID ASC

